import { useEffect, useState } from "react";

function App() {
  const [questions, setQuestions] = useState([]);

  useEffect(() => {
    fetch("http://localhost:3000/api/quiz")
      .then(res => res.json())
      .then(data => setQuestions(data));
  }, []);

  return (
    <div style={{
      padding: "30px",
      fontFamily: "Arial",
      backgroundColor: "#f5f5f5",
      minHeight: "100vh"
    }}>
      <h1>Online Exam - v1</h1>
      <h3>Harshith B - 23MIS0012</h3>

      {questions.map(q => (
        <div key={q.id} style={{
          background: "white",
          padding: "15px",
          marginBottom: "20px",
          borderRadius: "8px",
          boxShadow: "0 2px 5px rgba(0,0,0,0.1)"
        }}>
          <p><strong>{q.question}</strong></p>

          {q.options.map(opt => (
            <label key={opt} style={{ display: "block", margin: "5px 0" }}>
              <input type="radio" name={`q${q.id}`} /> {opt}
            </label>
          ))}
        </div>
      ))}
    </div>
  );
}

export default App;
